document.addEventListener("DOMContentLoaded",function(){const t=document.getElementById("modal"),e=document.getElementById("modal-img"),n=document.getElementById("modal-title"),d=document.getElementById("modal-desc"),o=document.getElementById("modal-link");t.style.display="none";function c(){t.style.display="none"}document.querySelectorAll(".project").forEach(c=>{c.addEventListener("click",function(){console.log("project",c);const l=this.getAttribute("data-src"),i=this.getAttribute("data-title"),a=this.getAttribute("data-desc"),s=this.getAttribute("data-link");e.src=l,n.innerText=i,d.innerText=a,o.href=s,t.style.display="flex"})}),t.addEventListener("click",function(e){e.target===t&&c()}),document.querySelector(".close").addEventListener("click",c)});